const p = $json.parcel_id || $json.folio || $json.property_number || null;
if(!p){ throw new Error('parcel_id/folio/property_number required'); }
return [{json:{...$json, parcel_id:p}}];

const row = {...$json};
const legal = (row.legal_description || '').toLowerCase();
const und = /\bund\b|undivided|fractional|parte ideal/.test(legal);
const badUse = /cemetery|roadway|drainage|common area|unusable/.test(`${row.use_code || ''} ${legal}`.toLowerCase());
const missingLegal = !row.legal_description || row.legal_description === 'unknown';
let discard = null;
let accessFlag = 'unknown';
if (/landlocked/.test(legal)) accessFlag = 'suspected_landlocked'; else accessFlag = 'ok';
if (und) discard = 'UND_OR_FRACTIONAL_INTEREST';
if (!discard && missingLegal) discard = 'MISSING_COMPLETE_LEGAL_DESCRIPTION';
if (!discard && badUse) discard = 'UNUSABLE_OR_RESTRICTED_LOT_TYPE';
return [{json:{...row, und_flag:und, access_flag:accessFlag, discard_reason:discard}}];
